import React from 'react';
import TimePanel from './panels/time-panel/index';
import type { PickerPanelProps } from '../interface';

function PickerPanel<DateType>(props: PickerPanelProps<DateType>) {
  // 根据 picker 类型分
  const { picker } = props;
  switch (picker) {
    case 'time':
      return <TimePanel<DateType> {...props} />;
    default:
      return <></>;
  }
}

export default PickerPanel;
